{
  "type": "Microsoft.Solutions/applications",
  "apiVersion": "2021-07-01",
  "name": "mywebapp",
  "location": "[resourceGroup().location]",
  "kind": "ServiceCatalog",
  "properties": {
    "managedResourceGroupId": "[subscriptionResourceId('Microsoft.Resources/resourceGroups', 'mywebapp-managed-rg')]",
    "applicationDefinitionId": "[parameters('definitionId')]",
    "parameters": {
      "appName": { "value": "[parameters('appName')]" },
      "environment": { "value": "prod" }
    }
  }
}

{
  "$schema": "https://schema.management.azure.com/schemas/0.1.2-preview/CreateUIDefinition.MultiVm.json#",
  "handler": "Microsoft.Azure.CreateUIDef",
  "version": "0.1.2-preview",
  "parameters": {
    "basics": [
      {
        "name": "appName",
        "type": "Microsoft.Common.TextBox",
        "label": "Application Name",
        "placeholder": "my-web-app",
        "constraints": {
          "required": true,
          "regex": "^[a-z0-9-]{3,24}$",
          "validationMessage": "3-24 lowercase letters, numbers, and hyphens"
        }
      }
    ],
    "steps": [
      {
        "name": "sizing",
        "label": "Sizing",
        "elements": [
          {
            "name": "appServiceSku",
            "type": "Microsoft.Common.DropDown",
            "label": "App Service Plan SKU",
            "defaultValue": "B1",
            "constraints": {
              "allowedValues": [
                { "label": "Basic B1 (Dev/Test)", "value": "B1" },
                { "label": "Standard S1", "value": "S1" },
                { "label": "Premium P1v3", "value": "P1v3" }
              ]
            }
          }
        ]
      }
    ],
    "outputs": {
      "appName": "[basics('appName')]",
      "appServiceSku": "[steps('sizing').appServiceSku]"
    }
  }
}

// mainTemplate.bicep — compiled into mainTemplate.json for the package
// Parameters come from createUiDefinition outputs
param appName string
param appServiceSku string = 'B1'
param location string = resourceGroup().location

resource plan 'Microsoft.Web/serverfarms@2023-01-01' = {
  name: '${appName}-plan'
  location: location
  sku: {
    name: appServiceSku
  }
  kind: 'linux'
  properties: {
    reserved: true
  }
}

resource app 'Microsoft.Web/sites@2023-01-01' = {
  name: appName
  location: location
  properties: {
    serverFarmId: plan.id
    httpsOnly: true
    siteConfig: {
      linuxFxVersion: 'NODE|20-lts'
      minTlsVersion: '1.2'
    }
  }
}

resource kv 'Microsoft.KeyVault/vaults@2023-02-01' = {
  name: '${appName}-kv'
  location: location
  properties: {
    sku: { family: 'A', name: 'standard' }
    tenantId: subscription().tenantId
    enableSoftDelete: true
    softDeleteRetentionInDays: 90
    enableRbacAuthorization: true
  }
}

output appUrl string = 'https://${app.properties.defaultHostName}'
output keyVaultId string = kv.id
